import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { RichTextEditor } from "@/components/admin/RichTextEditor";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { Save, Loader2, Eye } from "lucide-react";
import deepseekLogo from "@/assets/deepseek-logo.svg";

const AdminAboutUs = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [contentId, setContentId] = useState<string | null>(null);
  const [contentZh, setContentZh] = useState("");
  const [ichingText, setIchingText] = useState("");

  useEffect(() => {
    fetchContent();
  }, []);

  const fetchContent = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from("about_us_content")
      .select("*")
      .limit(1)
      .single();

    if (data) {
      setContentId(data.id);
      setContentZh(data.content_zh || "");
      setIchingText((data as any).iching_text || "");
    }
    if (error) console.error("Error fetching about us content:", error);
    setLoading(false);
  };

  const handleSave = async () => {
    if (!contentId) return;
    setSaving(true);
    // Save content_zh as the single source, sync to en/pt so existing fallback still works
    const { error } = await supabase
      .from("about_us_content")
      .update({
        content_zh: contentZh,
        content_en: contentZh,
        content_pt: contentZh,
        iching_text: ichingText,
        updated_at: new Date().toISOString(),
      } as any)
      .eq("id", contentId);

    if (error) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } else {
      toast({ title: t("common.success"), description: t("common.actions.saved", "已保存") });
    }
    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">{t("admin.aboutUs", "关于我们")}</h1>
          <p className="text-muted-foreground text-sm mt-1">
            编辑「关于我们」页面内容（单语言输入，前端自动翻译）
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => window.open("/about-us", "_blank")}>
            <Eye className="w-4 h-4 mr-2" />
            {t("common.preview", "预览")}
          </Button>
          <Button onClick={handleSave} disabled={saving}>
            {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            {t("common.actions.save")}
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">📝 主体内容</CardTitle>
          <CardDescription>关于我们的主要介绍（前端会自动翻译为用户的语言）</CardDescription>
        </CardHeader>
        <CardContent>
          <RichTextEditor
            value={contentZh}
            onChange={setContentZh}
            placeholder="输入关于我们的内容..."
            className="min-h-[400px]"
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">☰ 易经解读 <img src={deepseekLogo} alt="DeepSeek" className="h-5 w-5 inline-block" /></CardTitle>
          <CardDescription>默认显示中文，用户可点击翻译按钮手动翻译</CardDescription>
        </CardHeader>
        <CardContent>
          <Textarea
            value={ichingText}
            onChange={(e) => setIchingText(e.target.value)}
            placeholder="输入易经解读内容，例如：《易经·乾》：..."
            className="min-h-[200px] font-serif"
            rows={8}
          />
        </CardContent>
      </Card>
    </div>
  );
};

export default AdminAboutUs;
